randomNumber:
/* REXX Random Number Generation */

/* Seed the generator (optional but recommended) */
/* Using time is a common way, but granularity might be low */
CALL RANDOM 1, 999999, TIME('S') /* Seed with seconds */

/* Generate a random integer between 0 and 999 (default) */
random_int_default = RANDOM()
SAY 'Random Integer (0-999):' random_int_default

/* Generate a random integer within a specific range [min, max] (inclusive) */
min_val = 1
max_val = 100
random_int_range = RANDOM(min_val, max_val)
SAY 'Random Integer ['min_val'-'max_val']:' random_int_range

/* Generate multiple random numbers */
SAY '5 random numbers (1-10):'
DO 5 TIMES
  SAY RANDOM(1, 10)
END

/* Note: REXX typically doesn't have built-in float random in [0,1) */
/* You might simulate it: */
random_float_sim = RANDOM(0, 999999) / 1000000.0
SAY 'Simulated Random Float [0,1):' random_float_sim

EXIT

fileExists:
/* Check if a file exists using REXX stream function */
/* This feature might be specific to interpreters like Regina Rexx or ooRexx */

ARG path_to_check .
IF path_to_check = '' THEN path_to_check = 'rexx_exists_test.rex'

/* Create a dummy file */
CALL LINEOUT path_to_check, '/* Test file */', 1
CALL LINEOUT path_to_check

SAY "Checking path: '"path_to_check"'"

/* Use STREAM function with 'Query Exists' command */
file_info = stream(path_to_check, 'C', 'QUERY EXISTS')

IF file_info = '' THEN DO
    /* If it returns an empty string, the file/path likely doesn't exist */
    SAY " -> Does NOT exist (or cannot be accessed)."
END
ELSE DO
    /* If it returns the path name, it exists. */
    /* NOTE: This may not distinguish between file and directory easily */
    /* without further OS-specific calls or trying to open. */
    SAY " -> Exists (could be file or directory)."

    /* Attempt to query size as a hint for files (Regina specific?) */
    file_size = stream(path_to_check, 'C', 'QUERY SIZE')
    IF datatype(file_size, 'W') THEN
       SAY " -> Appears to be a file (query size returned number:" file_size")."
    ELSE
       SAY " -> Might be a directory (query size failed)."

END

/* Check a non-existent path */
non_existent = 'NoSuchThingHereRexx.xyz'
SAY "\nChecking path: '"non_existent"'"
file_info_ne = stream(non_existent, 'C', 'QUERY EXISTS')
IF file_info_ne = '' THEN
    SAY " -> Does NOT exist."
ELSE
    SAY " -> Exists? (Unexpected!)"


/* Clean up */
CALL stream path_to_check, 'C', 'DELETE'
SAY "\nCleaned up dummy file."

EXIT

