dateTime:
/* Get and format date and time using built-in functions */

SAY "--- Current Date and Time ---"

/* DATE() function */
SAY 'Date (default format, e.g., DD Mon YYYY):' DATE()
SAY 'Date (USA, MM/DD/YY):' DATE('U')
SAY 'Date (European, DD/MM/YY):' DATE('E')
SAY 'Date (Standard, YYYYMMDD):' DATE('S')
SAY 'Date (Sorted, YYYY/MM/DD):' DATE('O')
SAY 'Date (Weekday):' DATE('W') /* Full weekday name */
SAY 'Date (Full Month):' DATE('M') /* Full month name */
SAY 'Date (Day in year):' DATE('J') /* Julian day 1-366 */

/* TIME() function */
SAY '\nTime (default, HH:MM:SS):' TIME()
SAY 'Time (Civil, hh:MM[ap]m):' TIME('C') /* e.g., 10:30am */
SAY 'Time (Elapsed sec since midnight):' TIME('S')
SAY 'Time (Milliseconds since midnight):' TIME('M')
SAY 'Time (Hours since midnight):' TIME('H')
SAY 'Time (Normal, HH:MM:SS):' TIME('N') /* Same as default usually */
SAY 'Time (Reset elapsed timer):' TIME('R') /* Also returns elapsed since last R */

/* Combine Date and Time */
iso_date = DATE('S') /* YYYYMMDD */
iso_time = TIME('N') /* HH:MM:SS */
SAY '\nCombined Approx ISO:' iso_date'T'iso_time

/* Getting Unix Epoch Seconds is not standard built-in */
/* May require OS commands or external functions depending on interpreter */
/* Example using Regina Rexx external function (if enabled/available) */
/* address syscall 'time t' */
/* if rc == 0 then say '\nEpoch Seconds (syscall):' t */

EXIT
